    {
      "unit_name": "Unit I: Physical World and Measurements",
      "chapter_name": "Units and Measurements",
      "topic": "Physical World and Measurement",
      "outcomes": [
        "Understand the need for measurement and systems of units including SI fundamental and derived units.",
        "Apply rules for significant figures and determine uncertainty in results.",
        "Perform dimensional analysis and apply it to physical problems."
      ]
    },
    {
      "unit_name": "Unit II: Kinematics",
      "chapter_name": "Motion in a Straight Line",
      "topic": "Kinematics - Motion in a Straight Line",
      "outcomes": [
        "Define frame of reference and describe motion in a straight line."
      ]
    },
    {
      "unit_name": "Unit II: Kinematics",
      "chapter_name": "Motion in a Plane",
      "topic": "Kinematics - Motion in a Plane",
      "outcomes": [
        "Distinguish between scalar and vector quantities and perform vector addition/subtraction/multiplication."
      ]
    },
    {
      "unit_name": "Unit III: Laws of Motion",
      "chapter_name": "Laws of Motion",
      "topic": "Laws of Motion",
      "outcomes": [
        "Explain intuitive concepts of force, inertia, and Newton's three laws."
      ]
    },
    {
      "unit_name": "Unit IV: Work, Energy and Power",
      "chapter_name": "Work, Energy and Power",
      "topic": "Work, Energy and Power",
      "outcomes": [
        "Calculate work done by constant and variable forces."
      ]
    }
  ]
}
